-- Limpa pedidos de demo anteriores (mantém pedidos manuais com outros emails)
-- Execute no SQL Editor do Supabase
DELETE FROM pedidos
WHERE email ~ '@(construtorahorizonte|agrocerrado|terramax|infrabrasilsa|valeverdeltda|raposoconstrucoes|construmax|horizonte|serraauzl|berrocivil|litoral|obraprimaempreend|pinheirosouza|pantanal|frotatotal|rotacerta|logistica|caravellas|transbrasileiro|movimenta|sulexpresso|cerradoverde|boaesperanca|agroplus|grantasanta|cooperativaagro|campolargo|agromax|planaltocent|engenhariasubterranea|energiaverde|solarbrasil|pedreira|metalurgica|premoldados|estruturasmetalicas|montagens|processoindustrial|infraworks|obrasmunicipais|terraplanagem|saneamento|pavimenta|estradas).com.br$';

-- ── ATIVO (37 pedidos) ────────────────────────────────────────

-- ── ASSINADO (18 pedidos) ────────────────────────────────────────

-- ── CONTRATO_ENVIADO (22 pedidos) ────────────────────────────────────────

-- ── EM_ANALISE (28 pedidos) ────────────────────────────────────────

-- ── NOVO (30 pedidos) ────────────────────────────────────────

-- ── REJEITADO (15 pedidos) ────────────────────────────────────────

-- ── Confirmação ──────────────────────────────────────────────────────────────
SELECT status, COUNT(*) AS total
FROM pedidos
GROUP BY status
ORDER BY total DESC;